TeamConfig = {}
TeamConfig.teams = {}

function TeamConfig:init(teams)
    for _, team in pairs(teams) do
        local data = {}
        data.teamId = tonumber(team.teamId)
        data.areaId = tonumber(team.areaId)
        data.name = team.name
        self.teams[data.teamId] = data
    end
end

function TeamConfig:getTeam(teamId)
    local team = self.teams[teamId]
    if team == nil then
        team = self.teams[1]
    end
    return team
end
return TeamConfig
